"""Team Collaboration Manager.

Standard library only, ASCII only. Thread-safe in-memory implementation of a
team collaboration domain: users, projects, tasks, messaging, performance
analytics, and reporting.
"""

import copy
import csv
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Any, Callable, Dict, List, Optional, Tuple


# ---------------------------------------------------------------------------
# Sentinel for "argument not provided"
# ---------------------------------------------------------------------------
class _Unset:
    """Sentinel type to distinguish 'not passed' from an explicit None."""

    _instance = None

    def __new__(cls):
        if cls._instance is None:
            cls._instance = super().__new__(cls)
        return cls._instance

    def __repr__(self):
        return "<unset>"


_UNSET = _Unset()


# ---------------------------------------------------------------------------
# Enums
# ---------------------------------------------------------------------------
class TaskStatus(Enum):
    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(Enum):
    MEMBER = "member"
    ADMIN = "admin"


class ReportFormat(Enum):
    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exceptions
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base error for all team collaboration failures."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an operation."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint is violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with existing state."""


# ---------------------------------------------------------------------------
# Dataclasses
# ---------------------------------------------------------------------------
@dataclass
class Attachment:
    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class User:
    id: int
