    feedback: str
    task_id: Optional[int]
    created_at: datetime


# ---------------------------------------------------------------------------
# Shared state
# ---------------------------------------------------------------------------
class _State:
    """Holds the single shared lock, the global id counter, and all stores."""

    def __init__(self, now: Callable[[], datetime]):
        self.lock = threading.RLock()
        self.now = now
        self._next_id = 0

        # Primary stores keyed by id.
        self.users: Dict[int, User] = {}
        self.projects: Dict[int, Project] = {}
        self.tasks: Dict[int, Task] = {}
        self.messages: Dict[int, Message] = {}
        self.ratings: Dict[int, Rating] = {}

        # Indexes.
        self.project_tasks: Dict[int, List[int]] = {}
        self.assignee_tasks: Dict[int, List[int]] = {}
        self.project_messages: Dict[int, List[int]] = {}
        self.task_messages: Dict[int, List[int]] = {}
        self.ratee_ratings: Dict[int, List[int]] = {}

    def allocate_id(self) -> int:
        self._next_id += 1
        return self._next_id


# ---------------------------------------------------------------------------
# Helpers
# ---------------------------------------------------------------------------
def _valid_email(email: str) -> bool:
    return isinstance(email, str) and bool(email) and "@" in email


def build_pdf(lines: List[str]) -> bytes:
    """Build a minimal, valid single-page PDF from text lines.

    Only the ``b"%PDF-"`` prefix and bytes type are strictly required by the
    consumer, but this produces a well-formed minimal document.
    """
    def esc(text: str) -> str:
        return (
            text.replace("\\", "\\\\")
            .replace("(", "\\(")
            .replace(")", "\\)")
        )

    content_parts = ["BT", "/F1 12 Tf", "72 720 Td", "14 TL"]
    if not lines:
        lines = [""]
    first = True
    for line in lines:
        safe = esc("".join(ch for ch in str(line) if 32 <= ord(ch) < 127))
        if first:
            content_parts.append("({0}) Tj".format(safe))
            first = False
        else:
            content_parts.append("T* ({0}) Tj".format(safe))
    content_parts.append("ET")
    content_stream = "\n".join(content_parts)
    content_bytes = content_stream.encode("ascii")

    objects = []
    objects.append(b"<< /Type /Catalog /Pages 2 0 R >>")
    objects.append(b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>")
    objects.append(
        b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
        b"/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>"
    )
    objects.append(
        b"<< /Length "
        + str(len(content_bytes)).encode("ascii")
        + b" >>\nstream\n"
        + content_bytes
        + b"\nendstream"
    )
    objects.append(
        b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>"
    )

    out = bytearray()
    out += b"%PDF-1.4\n"
    offsets = []
    for idx, body in enumerate(objects, start=1):
        offsets.append(len(out))
        out += str(idx).encode("ascii") + b" 0 obj\n" + body + b"\nendobj\n"

    xref_pos = len(out)
    count = len(objects) + 1
    out += b"xref\n"
    out += b"0 " + str(count).encode("ascii") + b"\n"
    out += b"0000000000 65535 f \n"
    for off in offsets:
        out += ("%010d 00000 n \n" % off).encode("ascii")
    out += b"trailer\n"
    out += (
        b"<< /Size "
        + str(count).encode("ascii")
        + b" /Root 1 0 R >>\n"
    )
    out += b"startxref\n"
    out += str(xref_pos).encode("ascii") + b"\n"
    out += b"%%EOF"
    return bytes(out)


# ---------------------------------------------------------------------------
# Services
# ---------------------------------------------------------------------------
class _UserService:
    def __init__(self, state: _State):
        self._state = state
        self._lock = state.lock

    def _require_user(self, user_id: int) -> User:
        user = self._state.users.get(user_id)
        if user is None:
            raise NotFoundError("user {0} not found".format(user_id))
        return user

    def register_user(self, username, email, role=UserRole.MEMBER) -> User:
        with self._lock:
            if not isinstance(username, str) or not username.strip():
                raise ValidationError("username must be a non-empty string")
            if not _valid_email(email):
                raise ValidationError("invalid email")
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            username = username.strip()
            for existing in self._state.users.values():
                if existing.username == username:
                    raise DuplicateError("username already in use")
                if existing.email == email:
                    raise DuplicateError("email already in use")
            uid = self._state.allocate_id()
            user = User(
                id=uid,
                username=username,
                email=email,
                role=role,
                created_at=self._state.now(),
            )
            self._state.users[uid] = user
            self._state.assignee_tasks.setdefault(uid, [])
            return copy.deepcopy(user)

    def get_user(self, user_id) -> User:
        with self._lock:
            return copy.deepcopy(self._require_user(user_id))

    def list_users(self) -> List[User]:
        with self._lock:
            return [
                copy.deepcopy(self._state.users[uid])
                for uid in sorted(self._state.users)
            ]

    def update_user(
        self, user_id, username=_UNSET, email=_UNSET, role=_UNSET
    ) -> User:
        with self._lock:
            user = self._require_user(user_id)
            if username is not _UNSET:
                if not isinstance(username, str) or not username.strip():
                    raise ValidationError("username must be non-empty")
                new_name = username.strip()
                for other in self._state.users.values():
                    if other.id != user_id and other.username == new_name:
                        raise DuplicateError("username already in use")
                user.username = new_name
            if email is not _UNSET:
                if not _valid_email(email):
                    raise ValidationError("invalid email")
                for other in self._state.users.values():
                    if other.id != user_id and other.email == email:
                        raise DuplicateError("email already in use")
                user.email = email
            if role is not _UNSET:
                if not isinstance(role, UserRole):
                    raise ValidationError("role must be a UserRole")
                user.role = role
            return copy.deepcopy(user)

    def delete_user(self, user_id) -> None:
        with self._lock:
            self._require_user(user_id)
            for project in self._state.projects.values():
                if project.owner_id == user_id:
                    raise ConflictError("user owns a project")
            for task_id in self._state.assignee_tasks.get(user_id, []):
                task = self._state.tasks.get(task_id)
                if task is not None and task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has an open task")
            del self._state.users[user_id]
            self._state.assignee_tasks.pop(user_id, None)


class _ProjectService:
    def __init__(self, state: _State):
        self._state = state
        self._lock = state.lock

    def _require_project(self, project_id: int) -> Project:
        project = self._state.projects.get(project_id)
        if project is None:
            raise NotFoundError("project {0} not found".format(project_id))
        return project

    def create_project(
        self, name, start_date, end_date, owner_id, description=""
    ) -> Project:
        with self._lock:
            if owner_id not in self._state.users:
                raise NotFoundError("owner {0} not found".format(owner_id))
            if not isinstance(name, str) or not name.strip():
                raise ValidationError("project name must be non-empty")
            if end_date < start_date:
                raise ValidationError("end_date must be >= start_date")
            pid = self._state.allocate_id()
            project = Project(
                id=pid,
                name=name.strip(),
                description=description or "",
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
            )
            self._state.projects[pid] = project
            self._state.project_tasks.setdefault(pid, [])
            self._state.project_messages.setdefault(pid, [])
            return copy.deepcopy(project)

    def get_project(self, project_id) -> Project:
        with self._lock:
            return copy.deepcopy(self._require_project(project_id))

    def list_projects(self) -> List[Project]:
        with self._lock:
            return [
                copy.deepcopy(self._state.projects[pid])
                for pid in sorted(self._state.projects)
            ]

    def update_project(
        self,
        project_id,
        name=_UNSET,
        start_date=_UNSET,
        end_date=_UNSET,
        description=_UNSET,
    ) -> Project:
        with self._lock:
            project = self._require_project(project_id)
            new_name = project.name
            if name is not _UNSET:
                if not isinstance(name, str) or not name.strip():
                    raise ValidationError("project name must be non-empty")
                new_name = name.strip()
            new_start = project.start_date if start_date is _UNSET else start_date
            new_end = project.end_date if end_date is _UNSET else end_date
            if new_end < new_start:
                raise ValidationError("end_date must be >= start_date")
            project.name = new_name
            project.start_date = new_start
            project.end_date = new_end
            if description is not _UNSET:
                project.description = description or ""
            return copy.deepcopy(project)

    def delete_project(self, project_id) -> None:
        with self._lock:
            project = self._require_project(project_id)

            task_ids = list(self._state.project_tasks.get(project_id, []))
            for task_id in task_ids:
                task = self._state.tasks.pop(task_id, None)
                if task is not None and task.assignee_id is not None:
                    lst = self._state.assignee_tasks.get(task.assignee_id)
                    if lst is not None and task_id in lst:
                        lst.remove(task_id)
                # Remove messages attached to this task.
                msg_ids = list(self._state.task_messages.get(task_id, []))
                for mid in msg_ids:
                    self._state.messages.pop(mid, None)
                self._state.task_messages.pop(task_id, None)
            self._state.project_tasks.pop(project_id, None)

            msg_ids = list(self._state.project_messages.get(project_id, []))
            for mid in msg_ids:
                self._state.messages.pop(mid, None)
            self._state.project_messages.pop(project_id, None)

            del self._state.projects[project_id]


class _TaskService:
    def __init__(self, state: _State):
        self._state = state
        self._lock = state.lock

    def _require_task(self, task_id: int) -> Task:
        task = self._state.tasks.get(task_id)
        if task is None:
            raise NotFoundError("task {0} not found".format(task_id))
        return task

    def create_task(
        self, project_id, title, assignee_id=None, deadline=None, description=""
    ) -> Task:
        with self._lock:
            project = self._state.projects.get(project_id)
            if project is None:
                raise NotFoundError("project {0} not found".format(project_id))
            if assignee_id is not None and assignee_id not in self._state.users:
                raise NotFoundError("assignee {0} not found".format(assignee_id))
            if not isinstance(title, str) or not title.strip():
                raise ValidationError("title must be non-empty")
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline before project start")
            tid = self._state.allocate_id()
            task = Task(
                id=tid,
                project_id=project_id,
                title=title.strip(),
                description=description or "",
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                started_at=None,
                completed_at=None,
            )
            self._state.tasks[tid] = task
            self._state.project_tasks.setdefault(project_id, []).append(tid)
            if assignee_id is not None:
                self._state.assignee_tasks.setdefault(assignee_id, []).append(tid)
            return copy.deepcopy(task)

    def get_task(self, task_id) -> Task:
        with self._lock:
            return copy.deepcopy(self._require_task(task_id))

    def list_tasks_by_project(self, project_id) -> List[Task]:
        with self._lock:
            if project_id not in self._state.projects:
                raise NotFoundError("project {0} not found".format(project_id))
            ids = sorted(self._state.project_tasks.get(project_id, []))
            return [copy.deepcopy(self._state.tasks[t]) for t in ids]

    def list_tasks_by_assignee(self, assignee_id) -> List[Task]:
        with self._lock:
            if assignee_id not in self._state.users:
                raise NotFoundError("user {0} not found".format(assignee_id))
            ids = sorted(self._state.assignee_tasks.get(assignee_id, []))
            return [copy.deepcopy(self._state.tasks[t]) for t in ids]

    def _set_assignee(self, task: Task, new_assignee: Optional[int]) -> None:
        old = task.assignee_id
        if old is not None and old != new_assignee:
            lst = self._state.assignee_tasks.get(old)
            if lst is not None and task.id in lst:
                lst.remove(task.id)
        task.assignee_id = new_assignee
        if new_assignee is not None:
            dest = self._state.assignee_tasks.setdefault(new_assignee, [])
            if task.id not in dest:
                dest.append(task.id)

    def assign_task(self, task_id, assignee_id) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            if assignee_id not in self._state.users:
                raise NotFoundError("assignee {0} not found".format(assignee_id))
            self._set_assignee(task, assignee_id)
            return copy.deepcopy(task)

    def reassign_task(self, task_id, new_assignee_id) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            if new_assignee_id not in self._state.users:
                raise NotFoundError(
                    "assignee {0} not found".format(new_assignee_id)
                )
            self._set_assignee(task, new_assignee_id)
            return copy.deepcopy(task)

    def unassign_task(self, task_id) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._set_assignee(task, None)
            return copy.deepcopy(task)

    def set_deadline(self, task_id, deadline) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            if deadline is not None:
                project = self._state.projects.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError("deadline before project start")
            task.deadline = deadline
            return copy.deepcopy(task)

    def update_status(self, task_id, status) -> Task:
        with self._lock:
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")
            task = self._require_task(task_id)
            now = self._state.now()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            elif status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            task.status = status
            return copy.deepcopy(task)


class _MessageService:
    def __init__(self, state: _State):
        self._state = state
        self._lock = state.lock

    def _require_message(self, message_id: int) -> Message:
        msg = self._state.messages.get(message_id)
        if msg is None:
            raise NotFoundError("message {0} not found".format(message_id))
        return msg

    def post_message(
        self,
        author_id,
        body,
        project_id=None,
        task_id=None,
        parent_id=None,
        attachments=None,
    ) -> Message:
        with self._lock:
            if author_id not in self._state.users:
                raise NotFoundError("author {0} not found".format(author_id))
            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id/task_id required"
                )
            if project_id is not None and project_id not in self._state.projects:
                raise NotFoundError("project {0} not found".format(project_id))
            if task_id is not None and task_id not in self._state.tasks:
                raise NotFoundError("task {0} not found".format(task_id))
            if parent_id is not None and parent_id not in self._state.messages:
                raise NotFoundError("parent {0} not found".format(parent_id))

            att_list: List[Attachment] = []
            now = self._state.now()
            if attachments:
                for filename, data in attachments:
                    att_list.append(
                        Attachment(
                            filename=filename,
                            size=len(data),
                            uploaded_by=author_id,
                            uploaded_at=now,
                        )
                    )
            body_text = body if isinstance(body, str) else ""
            if not body_text.strip() and not att_list:
                raise ValidationError("message body or attachment required")

            mid = self._state.allocate_id()
            msg = Message(
                id=mid,
                author_id=author_id,
                body=body_text,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=att_list,
                created_at=now,
                edited_at=None,
            )
            self._state.messages[mid] = msg
            if project_id is not None:
                self._state.project_messages.setdefault(project_id, []).append(mid)
            if task_id is not None:
                self._state.task_messages.setdefault(task_id, []).append(mid)
            return copy.deepcopy(msg)

    def edit_message(self, message_id, editor_id, new_body) -> Message:
        with self._lock:
            msg = self._require_message(message_id)
            if msg.author_id != editor_id:
                raise AuthorizationError("only the author can edit")
            body_text = new_body if isinstance(new_body, str) else ""
            if not body_text.strip() and not msg.attachments:
                raise ValidationError("message body or attachment required")
            msg.body = body_text
            msg.edited_at = self._state.now()
            return copy.deepcopy(msg)

    def add_attachment(self, message_id, uploader_id, filename, data) -> Message:
        with self._lock:
            msg = self._require_message(message_id)
            if msg.author_id != uploader_id:
                raise AuthorizationError("only the author can add attachments")
            if not isinstance(filename, str) or not filename.strip():
                raise ValidationError("filename must be non-empty")
            msg.attachments.append(
                Attachment(
                    filename=filename,
                    size=len(data),
                    uploaded_by=uploader_id,
                    uploaded_at=self._state.now(),
                )
            )
            return copy.deepcopy(msg)

    def list_messages_by_project(self, project_id) -> List[Message]:
        with self._lock:
            if project_id not in self._state.projects:
                raise NotFoundError("project {0} not found".format(project_id))
            ids = sorted(self._state.project_messages.get(project_id, []))
            return [copy.deepcopy(self._state.messages[m]) for m in ids]

    def list_messages_by_task(self, task_id) -> List[Message]:
        with self._lock:
            if task_id not in self._state.tasks:
                raise NotFoundError("task {0} not found".format(task_id))
            ids = sorted(self._state.task_messages.get(task_id, []))
            return [copy.deepcopy(self._state.messages[m]) for m in ids]

    def delete_message(self, message_id, requester_id) -> None:
        with self._lock:
            msg = self._require_message(message_id)
            if msg.author_id != requester_id:
                raise AuthorizationError("only the author can delete")
            if msg.project_id is not None:
                lst = self._state.project_messages.get(msg.project_id)
                if lst is not None and message_id in lst:
                    lst.remove(message_id)
            if msg.task_id is not None:
                lst = self._state.task_messages.get(msg.task_id)
                if lst is not None and message_id in lst:
                    lst.remove(message_id)
            del self._state.messages[message_id]


class _PerformanceService:
    def __init__(self, state: _State):
        self._state = state
        self._lock = state.lock

    def _require_user(self, user_id: int) -> User:
        user = self._state.users.get(user_id)
        if user is None:
            raise NotFoundError("user {0} not found".format(user_id))
        return user

    def _user_tasks(self, user_id: int) -> List[Task]:
        ids = self._state.assignee_tasks.get(user_id, [])
        return [self._state.tasks[t] for t in ids if t in self._state.tasks]

    def get_completion_rate(self, user_id) -> float:
        with self._lock:
            self._require_user(user_id)
            tasks = self._user_tasks(user_id)
            if not tasks:
                return 0.0
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            return completed / len(tasks)

    def get_average_completion_time(self, user_id) -> Optional[float]:
        with self._lock:
            self._require_user(user_id)
            durations = []
            for t in self._user_tasks(user_id):
                if (
                    t.status == TaskStatus.COMPLETED
                    and t.started_at is not None
                    and t.completed_at is not None
                ):
                    durations.append(
                        (t.completed_at - t.started_at).total_seconds()
                    )
            if not durations:
                return None
            return sum(durations) / len(durations)

    def submit_rating(
        self, rater_id, ratee_id, score, feedback="", task_id=None
    ) -> Rating:
        with self._lock:
            if rater_id not in self._state.users:
                raise NotFoundError("rater {0} not found".format(rater_id))
            if ratee_id not in self._state.users:
                raise NotFoundError("ratee {0} not found".format(ratee_id))
            if rater_id == ratee_id:
                raise ConflictError("cannot rate yourself")
            if not isinstance(score, int) or isinstance(score, bool):
                raise ValidationError("score must be an integer 1..5")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            if task_id is not None and task_id not in self._state.tasks:
                raise NotFoundError("task {0} not found".format(task_id))
            rid = self._state.allocate_id()
            rating = Rating(
                id=rid,
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback or "",
                task_id=task_id,
                created_at=self._state.now(),
            )
            self._state.ratings[rid] = rating
            self._state.ratee_ratings.setdefault(ratee_id, []).append(rid)
            return copy.deepcopy(rating)

    def get_ratings_summary(self, user_id) -> Dict[str, Any]:
        with self._lock:
            self._require_user(user_id)
            ids = sorted(self._state.ratee_ratings.get(user_id, []))
            ratings = [self._state.ratings[r] for r in ids]
            count = len(ratings)
            if count == 0:
                average = 0.0
            else:
                average = sum(r.score for r in ratings) / count
            return {
                "count": count,
                "average": average,
                "ratings": [copy.deepcopy(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id) -> Dict[str, Any]:
        with self._lock:
            self._require_user(user_id)
            tasks = self._user_tasks(user_id)
            total = len(tasks)
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            in_progress = sum(
                1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
            )
            not_started = sum(
                1 for t in tasks if t.status == TaskStatus.NOT_STARTED
            )
            completion_rate = completed / total if total else 0.0
            avg_time = self.get_average_completion_time(user_id)
            summary = self.get_ratings_summary(user_id)
            return {
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completion_rate,
                "average_completion_time": avg_time,
                "rating_count": summary["count"],
                "rating_average": summary["average"],
            }


class _ReportService:
    def __init__(self, state: _State, performance: _PerformanceService):
        self._state = state
        self._lock = state.lock
        self._performance = performance

    def _task_stats(self, tasks: List[Task]) -> Dict[str, Any]:
        total = len(tasks)
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        in_progress = sum(
            1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
        )
        not_started = sum(
            1 for t in tasks if t.status == TaskStatus.NOT_STARTED
        )
        completion_rate = completed / total if total else 0.0
        return {
            "total_tasks": total,
            "completed_tasks": completed,
            "in_progress_tasks": in_progress,
            "not_started_tasks": not_started,
            "completion_rate": completion_rate,
        }

    def project_progress_report(self, project_id) -> Dict[str, Any]:
        with self._lock:
            if project_id not in self._state.projects:
                raise NotFoundError("project {0} not found".format(project_id))
            ids = self._state.project_tasks.get(project_id, [])
            tasks = [self._state.tasks[t] for t in ids if t in self._state.tasks]
            now = self._state.now()

            status_counts = {status.value: 0 for status in TaskStatus}
            for t in tasks:
                status_counts[t.status.value] += 1

            total = len(tasks)
            completed = status_counts[TaskStatus.COMPLETED.value]
            completion_rate = completed / total if total else 0.0

            overdue = 0
            for t in tasks:
                if (
                    t.deadline is not None
                    and t.deadline < now
                    and t.status != TaskStatus.COMPLETED
                ):
                    overdue += 1

            per_assignee: Dict[int, Dict[str, Any]] = {}
            for t in tasks:
                if t.assignee_id is None:
                    continue
                per_assignee.setdefault(t.assignee_id, [])
                per_assignee[t.assignee_id].append(t)
            per_assignee_stats = {
                uid: self._task_stats(tlist)
                for uid, tlist in per_assignee.items()
            }

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completion_rate,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee_stats,
            }

    def team_performance_report(self, project_id=None) -> Dict[str, Any]:
        with self._lock:
            if project_id is not None and project_id not in self._state.projects:
                raise NotFoundError("project {0} not found".format(project_id))

            if project_id is not None:
                ids = self._state.project_tasks.get(project_id, [])
                scope_tasks = [
                    self._state.tasks[t] for t in ids if t in self._state.tasks
                ]
            else:
                scope_tasks = list(self._state.tasks.values())

            by_user: Dict[int, List[Task]] = {}
            for t in scope_tasks:
                if t.assignee_id is None:
                    continue
                by_user.setdefault(t.assignee_id, []).append(t)

            rows = []
            for uid in sorted(by_user):
                tlist = by_user[uid]
                stats = self._task_stats(tlist)
                durations = [
                    (t.completed_at - t.started_at).total_seconds()
                    for t in tlist
                    if t.status == TaskStatus.COMPLETED
                    and t.started_at is not None
                    and t.completed_at is not None
                ]
                avg_time = (
                    sum(durations) / len(durations) if durations else None
                )
                row = {"user_id": uid}
                row.update(stats)
                row["average_completion_time"] = avg_time
                rows.append(row)

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id) -> Dict[str, Any]:
        with self._lock:
            if user_id not in self._state.users:
                raise NotFoundError("user {0} not found".format(user_id))
            ids = sorted(self._state.assignee_tasks.get(user_id, []))
            tasks = [self._state.tasks[t] for t in ids if t in self._state.tasks]
            stats = self._task_stats(tasks)
            task_entries = []
            for t in tasks:
                task_entries.append(
                    {
                        "task_id": t.id,
                        "project_id": t.project_id,
                        "title": t.title,
                        "status": t.status.value,
                        "started_at": t.started_at,
                        "completed_at": t.completed_at,
                        "deadline": t.deadline,
                    }
                )
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "total_tasks": stats["total_tasks"],
                "completed_tasks": stats["completed_tasks"],
                "in_progress_tasks": stats["in_progress_tasks"],
                "not_started_tasks": stats["not_started_tasks"],
                "completion_rate": stats["completion_rate"],
                "tasks": task_entries,
            }

    def export_report(self, report, fmt):
        if not isinstance(fmt, ReportFormat):
            raise ValidationError("fmt must be a ReportFormat")
        if not isinstance(report, dict):
            raise ValidationError("report must be a dict")
        if fmt == ReportFormat.CSV:
            return self._export_csv(report)
        return self._export_pdf(report)

    def _export_csv(self, report: Dict[str, Any]) -> str:
        buffer = io.StringIO()
        writer = csv.writer(buffer)
        rows = report.get("rows")
        if isinstance(rows, list) and rows:
            headers = []
            for row in rows:
                for key in row.keys():
                    if key not in headers:
                        headers.append(key)
            writer.writerow(headers)
            for row in rows:
                writer.writerow([self._csv_cell(row.get(h)) for h in headers])
        elif isinstance(rows, list):
            # rows present but empty: still emit a header row.
            writer.writerow(["report_type"])
            writer.writerow([self._csv_cell(report.get("report_type"))])
        else:
            writer.writerow(["key", "value"])
            for key, value in report.items():
                writer.writerow([key, self._csv_cell(value)])
        return buffer.getvalue()

    @staticmethod
    def _csv_cell(value: Any) -> str:
        if value is None:
            return ""
        if isinstance(value, (dict, list)):
            return str(value)
        return str(value)

    def _export_pdf(self, report: Dict[str, Any]) -> bytes:
        lines = []
        report_type = report.get("report_type", "report")
        lines.append("Report: {0}".format(report_type))
        rows = report.get("rows")
        if isinstance(rows, list):
            for row in rows:
                lines.append(
                    ", ".join(
                        "{0}={1}".format(k, v) for k, v in row.items()
                    )
                )
        else:
            for key, value in report.items():
                lines.append("{0}: {1}".format(key, value))
        return build_pdf(lines)


