class TeamCollaborationManager:
    """Facade exposing the full team collaboration API.

    All domain logic lives in the six service objects, which share a single
    reentrant lock and a single state object holding the global id counter.
    """

    def __init__(self, now: Optional[Callable[[], datetime]] = None):
        self._now = now if now is not None else datetime.now
        self._state = _State(self._now)
        self._lock = self._state.lock

        self.users = _UserService(self._state)
        self.projects = _ProjectService(self._state)
        self.tasks = _TaskService(self._state)
        self.messages = _MessageService(self._state)
        self.performance = _PerformanceService(self._state)
        self.reports = _ReportService(self._state, self.performance)

